const newData = $('Split Out').all();
const existing = $('Get Saved Leads1').all();

// Build a set of existing emails (case-insensitive, trimmed)
// Change "Email" to exactly match the column header in your Google Sheet
const existingEmails = new Set(
  existing
    .map(e => (e.json.Email || e.json.value || '').toLowerCase().trim())
    .filter(Boolean)
);

// Filter new data that is NOT already in the sheet
const filtered = newData.filter(b => {
  const email = (b.json.value || '').toLowerCase().trim();
  return email && !existingEmails.has(email);
});

// If no new leads, return a clear message
if (filtered.length === 0) {
  return [{
    json: {
      message: 'No new leads found',
      status: 'stopped'
    }
  }];
}

return filtered;

return $input.all().map(item => {
  // Get the raw text from the AI node
  let rawOutput = item.json.output || "";

  // 1. Find only the content between the first { and the last } 
  // This ignores the ```json and any other text the AI might have added
  const firstBracket = rawOutput.indexOf('{');
  const lastBracket = rawOutput.lastIndexOf('}');

  if (firstBracket === -1 || lastBracket === -1) {
    return { json: { error: "No JSON object found", raw: rawOutput } };
  }

  let jsonPart = rawOutput.substring(firstBracket, lastBracket + 1);

  try {
    // 2. Fix literal newlines: AI often puts real "Enters" in strings.
    // We replace actual newlines with the character string "\n" so it's valid JSON.
    // We target newlines that are NOT followed by a double quote and colon (which would be a key)
    const sanitizedJson = jsonPart.replace(/\n/g, "\\n")
                                  .replace(/\\n(?=\s*")/g, "") // remove newline before a key
                                  .replace(/\\n(?=\s*\})/g, ""); // remove newline before closing bracket

    // 3. Parse the cleaned string
    const parsedData = JSON.parse(sanitizedJson);

    return {
      json: parsedData
    };
  } catch (error) {
    return {
      json: {
        error: "Parse failed after cleanup",
        message: error.message,
        raw_fragment: jsonPart
      }
    };
  }
});

const output = $input.first().json.output;

function parseAssistantOutput(text) {
  const extract = (label) => {
    const match = text.match(new RegExp(`\\*\\*${label}\\*\\*:\\s*(.+)`));
    return match ? match[1].trim() : null;
  };

  return {
    assistantId: extract("Assistant ID"),
    assistantName: extract("Assistant Name"),
    creationTimestamp: extract("Creation Timestamp"),
    voice: extract("Voice"),
    purpose: extract("Purpose"),
  };
}

const result = parseAssistantOutput(output);

return [{ json: result }];
